     1→/**
     2→ * Knowledge graph page: force-directed visualization of sessions and knowledge links.
     3→ * Inline vanilla JS, no CDN dependencies.
     4→ */
     5→
     6→import type { ManifestEntry } from '../../types/transcript.js'
     7→import type { LinkGraph } from '../../types/report.js'
     8→import type { Translations } from '../i18n/types.js'
     9→import type { MarkdownFile } from './layout.js'
    10→import { escHtml, htmlShell, renderNav, transcriptUrlFromRoot } from './layout.js'
    11→
    12→const MAX_NODES = 500
    13→
    14→// ---------------------------------------------------------------------------
    15→// Graph data types
    16→// ---------------------------------------------------------------------------
    17→
    18→interface GraphNode {
    19→  id: string
    20→  label: string
    21→  type: 'session' | 'knowledge'
    22→  client?: string
    23→  url: string
    24→}
    25→
    26→interface GraphEdge {
    27→  source: string
    28→  target: string
    29→}
    30→
    31→// ---------------------------------------------------------------------------
    32→// Build graph data
    33→// ---------------------------------------------------------------------------
    34→
    35→export function buildGraphData(
    36→  manifests: ManifestEntry[],
    37→  knowledgeFiles: MarkdownFile[],
    38→  linkGraph: LinkGraph,
    39→): { nodes: GraphNode[]; edges: GraphEdge[] } {
    40→  // Cap manifests to MAX_NODES (most recent first)
    41→  const sorted = [...manifests]
    42→    .sort((a, b) => b.started_at.localeCompare(a.started_at))
    43→    .slice(0, MAX_NODES)
    44→
    45→  const nodeSet = new Set<string>()
    46→  const nodes: GraphNode[] = []
    47→  const edges: GraphEdge[] = []
    48→
    49→  for (const m of sorted) {
    50→    if (!nodeSet.has(m.session_id)) {
    51→      nodeSet.add(m.session_id)
    52→      nodes.push({
    53→        id: m.session_id,
    54→        label: m.title || m.session_id.slice(0, 8),
    55→        type: 'session',
    56→        client: m.client,
    57→        url: transcriptUrlFromRoot(m),
    58→      })
    59→    }
    60→  }
    61→
    62→  for (const kf of knowledgeFiles) {
    63→    const id = `knowledge:${kf.filename}`
    64→    if (!nodeSet.has(id)) {
    65→      nodeSet.add(id)
    66→      nodes.push({
    67→        id,
    68→        label: kf.title || kf.filename,
    69→        type: 'knowledge',
    70→        url: `knowledge/index.html#${slugify(kf.filename)}`,
    71→      })
    72→    }
    73→  }
    74→
    75→  // Add edges from link graph (only for nodes that exist)
    76→  for (const [sourceId, targets] of Object.entries(linkGraph.forwardLinks)) {
    77→    if (!nodeSet.has(sourceId)) continue
    78→    for (const targetId of targets) {
    79→      if (nodeSet.has(targetId)) {
    80→        edges.push({ source: sourceId, target: targetId })
    81→      }
    82→    }
    83→  }
    84→
    85→  return { nodes, edges }
    86→}
    87→
    88→function slugify(s: string): string {
    89→  return s.toLowerCase().replace(/[^a-z0-9]+/g, '-')
    90→}
    91→
    92→// ---------------------------------------------------------------------------
    93→// Graph page renderer
    94→// ---------------------------------------------------------------------------
    95→
    96→export function renderGraph(
    97→  manifests: ManifestEntry[],
    98→  knowledgeFiles: MarkdownFile[],
    99→  linkGraph: LinkGraph,
   100→  t?: Translations,
   101→): string {
   102→  const nav = renderNav('graph', 0, t)
   103→  const title = t?.graph.title ?? 'Knowledge Graph'
   104→  const subtitle = t?.graph.subtitle ?? 'Connections between sessions and knowledge files'
   105→
   106→  const { nodes, edges } = buildGraphData(manifests, knowledgeFiles, linkGraph)
   107→
   108→  if (nodes.length === 0) {
   109→    const content = `<div class="page-header">
   110→  <h1>${escHtml(title)}</h1>
   111→  <p class="subtitle">${escHtml(t?.graph.noData ?? 'No graph data available.')}</p>
   112→</div>`
   113→    return htmlShell(title, content, nav)
   114→  }
   115→
   116→  // Embed graph data as JSON; escape sequences that could break a <script> block
   117→  const graphDataJson = JSON.stringify({ nodes, edges })
   118→    .replace(/<\//g, '<\\/')
   119→    .replace(/\u2028/g, '\\u2028')
   120→    .replace(/\u2029/g, '\\u2029')
   121→
   122→  const graphScript = `<script>
   123→(function() {
   124→var GRAPH_DATA = ${graphDataJson};
   125→
   126→// Client color map
   127→var CLIENT_COLORS = { claude: '#bc8cff', codex: '#58a6ff', gemini: '#3fb950' };
   128→function nodeColor(n) {
   129→  if (n.type === 'knowledge') return '#f0c040';
   130→  return CLIENT_COLORS[n.client] || '#8b949e';
   131→}
   132→function nodeRadius(n) { return n.type === 'knowledge' ? 7 : 5; }
   133→
   134→var canvas = document.getElementById('graph-canvas');
   135→if (!canvas) return;
   136→var ctx = canvas.getContext('2d');
   137→
   138→// High-DPI
   139→function resize() {
   140→  var rect = canvas.getBoundingClientRect();
   141→  var dpr = window.devicePixelRatio || 1;
   142→  canvas.width = rect.width * dpr;
   143→  canvas.height = rect.height * dpr;
   144→  ctx.scale(dpr, dpr);
   145→}
   146→resize();
   147→window.addEventListener('resize', function() { resize(); draw(); });
   148→
   149→var W = canvas.getBoundingClientRect().width;
   150→var H = canvas.getBoundingClientRect().height;
   151→
   152→// Init positions (random spread)
   153→var nodeMap = {};
   154→var simNodes = GRAPH_DATA.nodes.map(function(n) {
   155→  var sn = { id: n.id, label: n.label, type: n.type, client: n.client, url: n.url,
   156→    x: W/2 + (Math.random()-0.5)*W*0.7, y: H/2 + (Math.random()-0.5)*H*0.7, vx: 0, vy: 0 };
   157→  nodeMap[n.id] = sn;
   158→  return sn;
   159→});
   160→
   161→var simEdges = GRAPH_DATA.edges.map(function(e) {
   162→  return { source: nodeMap[e.source], target: nodeMap[e.target] };
   163→}).filter(function(e) { return e.source && e.target; });
   164→
   165→// Simulation params
   166→var ALPHA = 1.0;
   167→var ALPHA_DECAY = 0.0228;
   168→var ALPHA_MIN = 0.001;
   169→var CHARGE = -120;
   170→var LINK_DIST = 80;
   171→var CENTER_FORCE = 0.05;
   172→var DAMPING = 0.6;
   173→
   174→// Pan/zoom state
   175→var panX = 0, panY = 0, scale = 1;
   176→var dragging = false, dragNode = null, dragOffX = 0, dragOffY = 0;
   177→var isPanning = false, panStartX = 0, panStartY = 0, panStartPanX = 0, panStartPanY = 0;
   178→
   179→function worldToScreen(wx, wy) {
   180→  return { x: (wx + panX) * scale + W/2, y: (wy + panY) * scale + H/2 };
   181→}
   182→function screenToWorld(sx, sy) {
   183→  return { x: (sx - W/2) / scale - panX, y: (sy - H/2) / scale - panY };
   184→}
   185→
   186→function tick() {
   187→  if (ALPHA < ALPHA_MIN) return;
   188→  ALPHA *= (1 - ALPHA_DECAY);
   189→
   190→  // Repulsion (n^2, capped)
   191→  var N = simNodes.length;
   192→  for (var i = 0; i < N; i++) {
   193→    for (var j = i+1; j < N; j++) {
   194→      var ni = simNodes[i], nj = simNodes[j];
   195→      var dx = nj.x - ni.x, dy = nj.y - ni.y;
   196→      var dist = Math.sqrt(dx*dx + dy*dy) || 1;
   197→      var force = CHARGE / (dist * dist) * ALPHA;
   198→      var fx = dx / dist * force, fy = dy / dist * force;
   199→      ni.vx -= fx; ni.vy -= fy;
   200→      nj.vx += fx; nj.vy += fy;
   201→    }
   202→  }
   203→
   204→  // Link attraction
   205→  for (var k = 0; k < simEdges.length; k++) {
   206→    var e = simEdges[k];
   207→    var dx2 = e.target.x - e.source.x, dy2 = e.target.y - e.source.y;
   208→    var dist2 = Math.sqrt(dx2*dx2 + dy2*dy2) || 1;
   209→    var strength = (dist2 - LINK_DIST) / dist2 * 0.5 * ALPHA;
   210→    var fx2 = dx2 * strength, fy2 = dy2 * strength;
   211→    e.source.vx += fx2; e.source.vy += fy2;
   212→    e.target.vx -= fx2; e.target.vy -= fy2;
   213→  }
   214→
   215→  // Center gravity
   216→  for (var m = 0; m < N; m++) {
   217→    var node = simNodes[m];
   218→    node.vx += -node.x * CENTER_FORCE * ALPHA;
   219→    node.vy += -node.y * CENTER_FORCE * ALPHA;
   220→    if (node === dragNode) continue;
   221→    node.vx *= DAMPING;
   222→    node.vy *= DAMPING;
   223→    node.x += node.vx;
   224→    node.y += node.vy;
   225→  }
   226→}
   227→
   228→function draw() {
   229→  W = canvas.getBoundingClientRect().width;
   230→  H = canvas.getBoundingClientRect().height;
   231→  ctx.clearRect(0, 0, W, H);
   232→  ctx.save();
   233→
   234→  // Draw edges
   235→  ctx.strokeStyle = 'rgba(139,148,158,0.3)';
   236→  ctx.lineWidth = 1;
   237→  for (var k = 0; k < simEdges.length; k++) {
   238→    var e = simEdges[k];
   239→    var s = worldToScreen(e.source.x, e.source.y);
   240→    var t2 = worldToScreen(e.target.x, e.target.y);
   241→    ctx.beginPath();
   242→    ctx.moveTo(s.x, s.y);
   243→    ctx.lineTo(t2.x, t2.y);
   244→    ctx.stroke();
   245→  }
   246→
   247→  // Draw nodes
   248→  for (var i = 0; i < simNodes.length; i++) {
   249→    var n = simNodes[i];
   250→    var pos = worldToScreen(n.x, n.y);
   251→    var r = nodeRadius(n) * scale;
   252→    ctx.beginPath();
   253→    ctx.arc(pos.x, pos.y, Math.max(r, 3), 0, Math.PI*2);
   254→    ctx.fillStyle = nodeColor(n);
   255→    ctx.fill();
   256→    if (n === hoverNode) {
   257→      ctx.strokeStyle = '#fff';
   258→      ctx.lineWidth = 1.5;
   259→      ctx.stroke();
   260→    }
   261→  }
   262→
   263→  // Draw hover label
   264→  if (hoverNode) {
   265→    var hpos = worldToScreen(hoverNode.x, hoverNode.y);
   266→    ctx.font = '11px sans-serif';
   267→    ctx.fillStyle = '#e6edf3';
   268→    ctx.fillText(hoverNode.label.slice(0, 30), hpos.x + 8, hpos.y - 4);
   269→  }
   270→
   271→  ctx.restore();
   272→}
   273→
   274→var hoverNode = null;
   275→
   276→function findNode(sx, sy) {
   277→  var w = screenToWorld(sx, sy);
   278→  var best = null, bestDist = Infinity;
   279→  for (var i = 0; i < simNodes.length; i++) {
   280→    var n = simNodes[i];
   281→    var dx = n.x - w.x, dy = n.y - w.y;
   282→    var dist = Math.sqrt(dx*dx + dy*dy);
   283→    if (dist < 15 / scale && dist < bestDist) { best = n; bestDist = dist; }
   284→  }
   285→  return best;
   286→}
   287→
   288→function getCanvasPos(evt) {
   289→  var rect = canvas.getBoundingClientRect();
   290→  return { x: evt.clientX - rect.left, y: evt.clientY - rect.top };
   291→}
   292→
   293→canvas.addEventListener('mousemove', function(e) {
   294→  var pos = getCanvasPos(e);
